const axios = require('axios');
try {
  const response = await axios.get('https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd');
  return `বিটকয়েনের বর্তমান মূল্য: $${response.data.bitcoin.usd} USD`;
} catch (error) {
  return 'দুঃখিত, বিটকয়েনের মূল্য এই মুহূর্তে আনা সম্ভব হচ্ছে না।';
}
